const ALLOW = new Set(['KubePodOOMKilled', 'KubePodCrashLoopBackOff']);
const body = $input.first().json.body ?? $input.first().json;
if (body.status === 'resolved') {
  return [{ json: { skip: true, reason: 'resolved', status: 'resolved' } }];
}
const alerts = body.alerts || [];
const first = alerts[0] || {};
const labels = { ...(body.commonLabels || {}), ...(first.labels || {}) };
const annotations = { ...(body.commonAnnotations || {}), ...(first.annotations || {}) };
const alertname = labels.alertname || body.groupLabels?.alertname || '';
if (!ALLOW.has(alertname)) {
  return [{ json: { skip: true, reason: 'not_allowlisted', alertname } }];
}
const namespace = labels.namespace || '';
const pod = labels.pod || labels.instance || '';
const container = labels.container || '';
const error = alertname === 'KubePodOOMKilled' ? 'OOMKilled' : 'CrashLoopBackOff';
return [{
  json: {
    skip: false,
    status: 'firing',
    alertname,
    namespace,
    pod,
    container,
    error,
    severity: labels.severity || 'critical',
    summary: annotations.summary || '',
    description: annotations.description || '',
    runbookUrl: annotations.runbook_url || '',
    fingerprint: first.fingerprint || '',
    raw: body,
  },
}];

